%[text] # Workflow HDF5 peakData Analysis Plot
%[text] This workflow shows different possibilities to plot data with the variable peakLaser.mat or peakVoltage.mat from the Workflow\_Calculate\_H.mlx and Workflow\_HDF5\_measurement\_condition.mlx
%[text] Both are table variables containing the specimen temperature, AnalysisUHV, pulsePeriod and pulseFraction/pulseEnergy for Voltage/Laser measurements
%[text] Following plots are contained in this workflow
%[text] 1. Load data 
%[text] 2. H conc vs AnalysisUHV
%[text] 3. H conc vs specimen Temperature
%[text] 4. H conc vs pulsePeriod
%[text] 5. Laser Measurement plots
%[text] 6. Voltage Measurement plots
%[text] 7. Save Image \
%%
%[text] ## 1. Load the data
load('L:\existingHDF5files\peakLaser.mat')
load('L:\existingHDF5files\peakVoltage.mat')
%%
%[text] ## 2. H conc vs AnalysisUHV
figure; %[output:92a6b008]
scatter(peakLaser.AnalysisUHV, peakLaser.pctNew, 'filled', 'MarkerFaceColor',  blau(1,:), 'DisplayName', 'Laser'); %[output:92a6b008]
hold on %[output:92a6b008]
scatter(peakVoltage.AnalysisUHV, peakVoltage.pctNew, 'filled', 'MarkerFaceColor',  gelb(1,:), 'DisplayName', 'Voltage'); %[output:92a6b008]
legend %[output:92a6b008]
ylabel('H conc in pct'); %[output:92a6b008]
xlabel('Analysis UHV in torr'); %[output:92a6b008]
%%
%[text] ### H conc vs AnalysisUHV with pulsePeriod
figure; %[output:549f9a79]
attrLaser = flip(unique(peakLaser.pulsePeriod));
for i = 1:length(attrLaser)
    scatter(peakLaser.AnalysisUHV(peakLaser.pulsePeriod == attrLaser(i)), peakLaser.pctNew(peakLaser.pulsePeriod == attrLaser(i)), 'filled', 'MarkerFaceColor',  blau(i,:), 'DisplayName', ['Laser ' num2str(attrLaser(i))]); %[output:549f9a79]
    hold on
end
attrVoltage = flip(unique(peakVoltage.pulsePeriod));
for i = 1:length(attrVoltage)
    scatter(peakVoltage.AnalysisUHV(peakVoltage.pulsePeriod == attrVoltage(i)), peakVoltage.pctNew(peakVoltage.pulsePeriod == attrVoltage(i)), 'filled', 'MarkerFaceColor',  gelb(i,:),'DisplayName', ['Voltage ' num2str(attrVoltage(i))]); %[output:549f9a79]
    hold on
end

legend %[output:549f9a79]
ylabel('H conc in pct'); %[output:549f9a79]
xlabel('Analysis UHV in torr'); %[output:549f9a79]
%%
%[text] ## 3. H conc vs specimen Temperature
figure; %[output:1831523f]
scatter(peakLaser.SpecTemp, peakLaser.pctNew, 'filled', 'DisplayName', 'Laser', 'MarkerFaceColor',blau(1,:)); %[output:1831523f]
hold on %[output:1831523f]
scatter(peakVoltage.SpecTemp, peakVoltage.pctNew, 'filled', 'DisplayName', 'Voltage', 'MarkerFaceColor',gelb(1,:)); %[output:1831523f]
legend %[output:1831523f]
ylabel('H conc in pct'); %[output:1831523f]
xlabel('specimen temperature in K'); %[output:1831523f]
%%
%[text] ## 4. H conc vs pulsePeriod
figure; %[output:7044d4f7]
scatter(peakLaser.pulsePeriod, peakLaser.pctNew, 'filled', 'DisplayName', 'Laser'); %[output:7044d4f7]
hold on %[output:7044d4f7]
scatter(peakVoltage.pulsePeriod, peakVoltage.pctNew, 'filled', 'DisplayName', 'Voltage'); %[output:7044d4f7]
legend %[output:7044d4f7]
ylabel('H conc in pct'); %[output:7044d4f7]
xlabel('pulsePeriod in kHz'); %[output:7044d4f7]
%%
%[text] ## 5. Laser measurement plots
%[text] ### H conc vs pulse Energy
figure; %[output:6498611e]
scatter(peakLaser.pulseEnergy, peakLaser.pctNew, 'filled', 'DisplayName', 'Laser'); %[output:6498611e]
legend %[output:6498611e]
ylabel('H conc in pct'); %[output:6498611e]
xlabel('pulseEnergy in nJ'); %[output:6498611e]
%%
%[text] ### H conc vs Analysis UHV in dependence of pulsePeriod
attr = flip(unique(peakLaser.pulsePeriod));
figure; %[output:235f6c58]
for i = 1:length(attr)
    scatter(peakLaser.AnalysisUHV(peakLaser.pulsePeriod == attr(i)), peakLaser.pctNew(peakLaser.pulsePeriod == attr(i)), 'filled', 'DisplayName', num2str(attr(i))); %[output:235f6c58]
    hold on
end
legend %[output:235f6c58]
ylabel('H conc in pct'); %[output:235f6c58]
xlabel('Analysis UHV in torr'); %[output:235f6c58]
%%
%[text] ### H conc vs Analysis UHV in dependence of pulseEnergy
attr = flip(unique(peakLaser.pulseEnergy));
figure; %[output:46ff0d8d]
for i = 1:length(attr)
    scatter(peakLaser.AnalysisUHV(peakLaser.pulseEnergy == attr(i)), peakLaser.pctNew(peakLaser.pulseEnergy == attr(i)), 'filled', 'DisplayName', [num2str(attr(i)*1000) ' pJ']); %[output:46ff0d8d]
    hold on
end
legend %[output:46ff0d8d]
ylabel('H conc in pct'); %[output:46ff0d8d]
xlabel('Analysis UHV in torr'); %[output:46ff0d8d]
%%
%[text] ### H conc vs Analysis UHV in dependence of specimen Temperature
%[text] Specimen temperature is rounded to have a clearer overview
specNewTemp = round(peakLaser.SpecTemp);
attr = unique(specNewTemp);
figure; %[output:50efe504]
for i = 1:length(attr)
   scatter(peakLaser.AnalysisUHV(specNewTemp == attr(i)), peakLaser.pctNew(specNewTemp == attr(i)), 'filled', 'DisplayName', ['Temp ' num2str(attr(i)) ' K']); %[output:50efe504]
   hold on
end
legend %[output:50efe504]
ylabel('H conc in pct'); %[output:50efe504]
xlabel('Analysis UHV in torr'); %[output:50efe504]
%%
%[text] ### H conc vs specimen Temperature
attr = unique(peakLaser.pulseEnergy);
figure; %[output:87f4f35c]
for i = 1:length(attr)
    scatter(peakLaser.SpecTemp(peakLaser.pulseEnergy == attr(i)), peakLaser.pctNew(peakLaser.pulseEnergy == attr(i)), 'filled', 'DisplayName', [num2str(attr(i)*1000) ' pJ']); %[output:87f4f35c]
    hold on
end
legend %[output:87f4f35c]
ylabel('H conc in pct'); %[output:87f4f35c]
xlabel('specimen temperature in K'); %[output:87f4f35c]
%[text] 
%%
%[text] ## 6. Voltage measurement plots
%[text] ### H conc vs Analysis UHV in dependence of pulsePeriod
figure; %[output:9a3b2f75]
attr = flip(unique(peakVoltage.pulsePeriod));
for i = 1:length(attr)
    scatter(peakVoltage.AnalysisUHV(peakVoltage.pulsePeriod == attr(i)), peakVoltage.pctNew(peakVoltage.pulsePeriod == attr(i)), 'filled', 'DisplayName', [num2str(attr(i))]); %[output:9a3b2f75]
    hold on
end

legend %[output:9a3b2f75]
ylabel('H conc in pct'); %[output:9a3b2f75]
xlabel('Analysis UHV in torr'); %[output:9a3b2f75]
%%
%[text] ### H conc vs Analysis UHV in dependence of pulseFraction
attr = flip(unique(peakVoltage.pulseFraction));
figure; %[output:3ec19863]
for i = 1:length(attr)
    scatter(peakVoltage.AnalysisUHV(peakVoltage.pulseFraction == attr(i)), peakVoltage.pctNew(peakVoltage.pulseFraction == attr(i)), 'filled', 'DisplayName', num2str(attr(i)));
    hold on
end
legend %[output:3ec19863]
ylabel('H conc in pct'); %[output:3ec19863]
xlabel('Analysis UHV in torr'); %[output:3ec19863]
%%
%[text] ### H conc vs Analysis UHV in dependence of specimen Temperature
%[text] Specimen temperature is rounded to have a clearer overview
specNewTemp = round(peakVoltage.SpecTemp);

specNewTemp(specNewTemp == 44) = 45;
specNewTemp(specNewTemp == 49) = 50;
specNewTemp(specNewTemp == 62) = 60;
specNewTemp(specNewTemp == 63) = 60;
attr = unique(specNewTemp);
figure; %[output:388adbae]
for i = 1:length(attr)
   scatter(peakVoltage.AnalysisUHV(specNewTemp == attr(i)), peakVoltage.pctNew(specNewTemp == attr(i)), 'filled', 'DisplayName', ['Temp ' num2str(attr(i)) ' K']); %[output:388adbae]
   hold on
end
legend %[output:388adbae]
ylabel('H conc in pct'); %[output:388adbae]
xlabel('Analysis UHV in torr'); %[output:388adbae]
%%
%[text] ### 7. Save figure
fig = gcf;
       
        nameForSave = ""; %[control:editfield:46e1]{"position":[23,25]}
        savefig(fig, nameForSave);
        saveas(fig,nameForSave,'tif'); %[output:95e59403]
        exportgraphics(fig,[string(nameForSave) + ".eps"],'Resolution',600); %[output:95e59403]
%[text] 
